export function nextGeneration(board: unknown[]): unknown[] {
  if (board.length === 0) return [];
  if (board.length === 1) return [];

  // For exactly 2 cells: keep both (stable pair)
  if (board.length === 2) {
    const [cell1, cell2] = board as number[][];
    if (areAdjacent(cell1, cell2)) return board;
    return [];
  }

  // For 3 or more cells: full generation logic
  const boardArray = board as number[][];

  // Keep cells that survive
  const survivors = boardArray.filter(cell => survivesByPopulation(cell, board));

  // Find potential new cells (candidates from neighbors of existing cells)
  const candidates = new Set<string>();
  for (const cell of boardArray) {
    // Add all adjacent cells as candidates for reproduction
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue; // Skip the cell itself
        const candidateCoords = [cell[0] + dx, cell[1] + dy];
        // Only consider if not already alive
        const isAlive = boardArray.some(c => c[0] === candidateCoords[0] && c[1] === candidateCoords[1]);
        if (!isAlive) {
          candidates.add(candidateCoords.toString());
        }
      }
    }
  }

  // Add cells that should be born
  const newCells: number[][] = [];
  for (const coordStr of candidates) {
    const coords = coordStr.split(',').map(Number);
    const deadCell = [coords[0], coords[1]];
    if (shouldReproduce(deadCell, board)) {
      newCells.push(deadCell);
    }
  }

  // Combine survivors and new cells, then sort for consistent output
  const result = [...survivors, ...newCells].sort((a, b) => {
    if (a[0] !== b[0]) return a[0] - b[0];
    return a[1] - b[1];
  });

  return result;
}

